-- ============================================================
-- ZARODA SMS — Assessment Report Book (KICD strand/sub-strand)
-- Templates (global, per grade × learning area) + per-learner scores.
-- Auto-runs on startup (idempotent).
-- ============================================================

-- Template: one per grade × learning area. tenant_id NULL = global KICD seed.
CREATE TABLE IF NOT EXISTS assessment_templates (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_id     UUID,                       -- NULL = global; set = school override
  grade_level   VARCHAR(40) NOT NULL,
  learning_area VARCHAR(120) NOT NULL,
  created_at    TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_atpl_grade ON assessment_templates(grade_level, learning_area);

-- Strands within a template
CREATE TABLE IF NOT EXISTS assessment_strands (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  template_id UUID NOT NULL REFERENCES assessment_templates(id) ON DELETE CASCADE,
  position    INT NOT NULL DEFAULT 0,
  name        VARCHAR(200) NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_astrand_tpl ON assessment_strands(template_id);

-- Sub-strands within a strand (each gets a YouTube resource link)
CREATE TABLE IF NOT EXISTS assessment_substrands (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  strand_id   UUID NOT NULL REFERENCES assessment_strands(id) ON DELETE CASCADE,
  position    INT NOT NULL DEFAULT 0,
  name        VARCHAR(300) NOT NULL,
  youtube_url VARCHAR(400)                 -- learning resource per sub-strand
);
CREATE INDEX IF NOT EXISTS idx_asub_strand ON assessment_substrands(strand_id);

-- Per-learner score: one row per sub-strand per learner per term
CREATE TABLE IF NOT EXISTS assessment_scores (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_id     UUID NOT NULL,
  learner_id    UUID NOT NULL,
  stream_id     UUID,
  grade_level   VARCHAR(40),
  learning_area VARCHAR(120),
  substrand_id  UUID NOT NULL,
  term          VARCHAR(20) NOT NULL,
  level         VARCHAR(4),               -- EE / ME / AE / BE
  recorded_by   UUID,
  updated_at    TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE (learner_id, substrand_id, term)
);
CREATE INDEX IF NOT EXISTS idx_ascore_lookup ON assessment_scores(tenant_id, learner_id, learning_area, term);
CREATE INDEX IF NOT EXISTS idx_ascore_stream ON assessment_scores(tenant_id, stream_id, term);

-- Seed assessment book templates from KICD books (idempotent)
DO $$
DECLARE tid UUID; sid UUID;
BEGIN
  DELETE FROM assessment_substrands WHERE strand_id IN (SELECT st.id FROM assessment_strands st JOIN assessment_templates t ON t.id=st.template_id WHERE t.tenant_id IS NULL);
  DELETE FROM assessment_strands WHERE template_id IN (SELECT id FROM assessment_templates WHERE tenant_id IS NULL);
  DELETE FROM assessment_templates WHERE tenant_id IS NULL;
END $$;
-- Per-learner teacher comment for a learning area + term
CREATE TABLE IF NOT EXISTS assessment_comments (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  tenant_id     UUID NOT NULL,
  learner_id    UUID NOT NULL,
  learning_area VARCHAR(120) NOT NULL,
  term          VARCHAR(20) NOT NULL,
  comment       TEXT,
  recorded_by   UUID,
  updated_at    TIMESTAMPTZ DEFAULT NOW(),
  UNIQUE (learner_id, learning_area, term)
);
CREATE INDEX IF NOT EXISTS idx_acomment_lookup ON assessment_comments(tenant_id, learner_id, term);
